function f(e){return new Date(e).toLocaleDateString(void 0,{day:"2-digit",month:"short",year:"numeric"})}function u(e){const o=new Date(e).getTime();if(Number.isNaN(o))return"Recently";const t=Date.now()-o,n=1e3*60,a=n*60,r=a*24,i=r*7;return t<n?"Just now":t<a?`${Math.max(1,Math.floor(t/n))} min ago`:t<r?`${Math.max(1,Math.floor(t/a))} hr ago`:t<r*2?"Yesterday":t<i?`${Math.max(2,Math.floor(t/r))} days ago`:f(e)}export{u as f};
